"use client";

import { Slider as SliderPrimitive } from "@base-ui/react/slider";
import * as stylex from "@stylexjs/stylex";
import * as React from "react";
import {
	sliderControlStyles,
	sliderStyles,
	sliderTrackStyles,
	thumbStateStyles,
} from "./slider.styles";

type SliderProps = Omit<SliderPrimitive.Root.Props, "style"> & {
	style?: stylex.StyleXStyles;
};

type SliderValueProps = Omit<SliderPrimitive.Value.Props, "style"> & {
	style?: stylex.StyleXStyles;
};

function Slider({
	className,
	children,
	defaultValue,
	value,
	min = 0,
	max = 100,
	style,
	...props
}: SliderProps): React.ReactElement {
	const values = React.useMemo(() => {
		if (value !== undefined) {
			return Array.isArray(value) ? value : [value];
		}
		if (defaultValue !== undefined) {
			return Array.isArray(defaultValue) ? defaultValue : [defaultValue];
		}
		return [min];
	}, [value, defaultValue, min]);
	const orientation = props.orientation || "horizontal";
	const rootProps = stylex.props(
		props.disabled && sliderStyles.disabled,
		style,
	);

	return (
		<SliderPrimitive.Root
			className={[rootProps.className, className].filter(Boolean).join(" ")}
			defaultValue={defaultValue}
			max={max}
			min={min}
			thumbAlignment="edge"
			value={value}
			{...props}
		>
			{children}
			<SliderPrimitive.Control
				className={
					stylex.props(sliderStyles.control, sliderControlStyles[orientation])
						.className
				}
				data-slot="slider-control"
			>
				<SliderPrimitive.Track
					className={
						stylex.props(sliderStyles.track, sliderTrackStyles[orientation])
							.className
					}
					data-slot="slider-track"
				>
					<SliderPrimitive.Indicator
						className={stylex.props(sliderStyles.indicator).className}
						data-slot="slider-indicator"
					/>
					{Array.from({ length: values.length }, (_, index) => (
						<SliderPrimitive.Thumb
							index={index}
							key={index}
							render={(thumbRenderProps, state) => (
								<div
									{...thumbRenderProps}
									className={[
										thumbRenderProps.className,
										stylex.props(
											sliderStyles.thumb,
											state.dragging && thumbStateStyles.dragging,
											state.disabled && sliderStyles.disabled,
										).className,
									]
										.filter(Boolean)
										.join(" ")}
								/>
							)}
						/>
					))}
				</SliderPrimitive.Track>
			</SliderPrimitive.Control>
		</SliderPrimitive.Root>
	);
}

function SliderValue({
	className,
	style,
	...props
}: SliderValueProps): React.ReactElement {
	return (
		<SliderPrimitive.Value
			className={[stylex.props(sliderStyles.value, style).className, className]
				.filter(Boolean)
				.join(" ")}
			data-slot="slider-value"
			{...props}
		/>
	);
}

export { SliderValue, Slider };

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import {
	borderRadius,
	borderWidth,
	fontSize,
	mediaQueries,
} from "@/lib/theme/tokens.stylex";
export const thumbStateStyles = stylex.create({
	dragging: {
		transform: "scale(1.2)",
		boxShadow: "none",
	},
});
export const sliderControlStyles = stylex.create({
	horizontal: {
		width: "100%",
		minWidth: 176,
		height: 7,
	},
	vertical: {
		height: "100%",
		minHeight: 176,
		flexDirection: "column",
	},
});
export const sliderTrackStyles = stylex.create({
	horizontal: {
		width: "100%",
		height: 7,
	},
	vertical: {
		height: "100%",
	},
});
export const sliderStyles = stylex.create({
	disabled: {
		pointerEvents: "none",
		opacity: 0.64,
	},
	control: {
		display: "flex",
		touchAction: "none",
		userSelect: "none",
	},
	track: {
		position: "relative",
		flexGrow: 1,
		userSelect: "none",
		borderRadius: borderRadius.full,
		backgroundColor: theme.border,
	},
	indicator: {
		userSelect: "none",
		borderRadius: borderRadius.full,
		backgroundColor: theme.primary,
	},
	thumb: {
		display: "block",
		flexShrink: 0,
		userSelect: "none",
		borderRadius: borderRadius.full,
		borderWidth: borderWidth.thin,
		borderStyle: "solid",
		borderColor: theme.border,
		backgroundColor: theme.surface,
		outline: "none",
		transitionProperty: "box-shadow, transform",
		transitionDuration: "150ms",
		width: {
			default: 16,
			[mediaQueries.sm]: 14,
		},
		height: {
			default: 16,
			[mediaQueries.sm]: 14,
		},
		boxShadow: {
			default: theme.shadowSm,
			":has(:focus-visible)": `0 0 0 3px ${theme.focusRing}`,
			// "&[data-dragging]": "none",
		},
		transform: {
			default: "none",
			// "&[data-dragging]": "scale(1.2)",
		},
	},
	value: {
		display: "flex",
		justifyContent: "flex-end",
		fontSize: fontSize.small,
	},
});
